={{ (() => {
  const attachments = $json.attachments || [];
  const text = $json.message_text || '';
  if (attachments.length === 0) return text;
  const urlList = attachments.map((a, i) => `[Attachment ${i+1}]: ${a.url} (${a.filename}, ${a.type})`).join('\n');
  return `⚠️ ATTACHMENT — you cannot view this directly. Call the appropriate tool NOW.\n${urlList}\n\n${text}`;
})() }}

